INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'hostels', 'Hostels > Boys Summary: 11 boys hostels (H1-H11). H1, H2, H3 are for 1st years with 3-sharing rooms. H4-H7 are for 2nd/3rd years with 1-2 sharing. H8, H9 are for 3rd years with single rooms. H10 is for 2nd/3rd/4th years with mixed sharing. H11 is for MTech/PhD with 2 sharing. Mess is inside the hostel.');
