INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'fee_structure', 'Fee Structure > General/OBC/EWS (Income > 5L) > Hostel Room Rent: Triple sharing Rs 4,200/sem, Double sharing Rs 7,300/sem, Single sharing Rs 10,500/sem.');
