INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'language', 'Language > Hindi is the primary language spoken in and around NIT Kurukshetra.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'climate', 'Climate > Extremely cold in January-February. Mildly cold in October-December. Extremely hot in June-August. Mildly hot in March-May. Kurukshetra experiences extreme seasonal variations.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'academics', 'Academics > NIT Kurukshetra offers 15 B.Tech branches: Architecture & Planning, AI & Data Science, AI & Machine Learning, Civil Engineering, Computer Science & Engineering, Electrical Engineering, Electronics & Communication Engineering, Industrial Internet of Things, Information Technology, Mathematics & Computing, Mechanical Engineering, Microelectronics & VLSI, Production & Industrial Engineering, Robotics & Automation, Sustainable Energy Technologies.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'academics', 'Academics > 1st Semester common subjects for Group-I (CSE, ECE, IT, AI, IIoT, MC): Communication Skills in English (HSIC101), Financial Education (HSIC103), Differential Calculus and Differential Equations (MAIC101), Engineering Physics (PHIC101), Engineering Practice (MEIC102), Problem Solving and Programming Using C (CSIC101), Energy and Environmental Science (CHIC101).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'academics', 'Academics > 1st Semester common subjects for Group-II (EE, CE, ME, PIE, RA, SET, MV): Economics for Engineers (HSIC102), Business Studies (HSIC104), Differential Calculus (MAIC101), Engineering Physics (PHIC101), Engineering Graphics (CEIC101/MEIC101), Problem Solving and Programming Using C (CSIC103), Energy and Environmental Science (CHIC101).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'academics', 'Academics > Class timings: 10 periods per day. Winter starts 9:00 AM, Summer starts 8:00 AM. Each class is 1 hour duration. Classes run Monday to Friday with Saturday following rotating schedule per academic calendar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'academics', 'Academics > Lecture halls: L1-L6 in Electronics Department, A210 and A325 in A Block, EHGF/EHFF (Exam Hall Ground/First Floor), NTB (New Teaching Block). Labs in respective departments.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Kurukshetra', 'academics', 'Academics > Extracurricular slots: NCC/Sports/Yoga and NSS/Clubs/Technical Societies have dedicated time slots in the timetable (typically Tuesday afternoons).');
